html, body, #map {
  width: 100%;
  height: 100%;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

#legend {
  position: absolute;
  bottom: 30px;
  right: 10px;
  background: rgba(255,255,255,0.92);
  padding: 12px 16px;
  border-radius: 8px;
  font-size: 13px;
  line-height: 1.6;
  box-shadow: 0 2px 8px rgba(0,0,0,0.2);
  z-index: 10;
}

#legend h3 {
  margin-bottom: 6px;
  font-size: 13px;
}

.legend-row {
  display: flex;
  align-items: center;
  gap: 8px;
}

.swatch {
  display: inline-block;
  width: 18px;
  height: 14px;
  border: 1px solid #999;
  border-radius: 2px;
}

#loading {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  background: rgba(255,255,255,0.85);
  z-index: 100;
  transition: opacity 0.4s;
}

#loading.hidden {
  opacity: 0;
  pointer-events: none;
}

.spinner {
  width: 40px;
  height: 40px;
  border: 4px solid #ccc;
  border-top-color: #2171b5;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin { to { transform: rotate(360deg); } }

.maplibregl-popup-content {
  font-size: 13px;
  padding: 8px 12px;
}

